"use client";

import { useState, useRef } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import {
  getRandomComplete,
  getRandomEncourage,
} from "@/lib/learningMessages";
import { getNextStep } from "@/content";
import { playStep, playCelebrate } from "@/lib/sounds";

// 竖式步骤
type DivisionStep = {
  title: string;
  hint: string;
  highlightCells: string[]; // 用于标记竖式中高亮的单元格 id
};

const DIVISION_STEPS: DivisionStep[] = [
  {
    title: "先分十位：3 ÷ 3 = 1",
    hint: "小棒操作：先把 3 捆（30根）平均分给 3 个同学，每人 1 捆",
    highlightCells: ["q-ten", "r-ten", "mul-1", "sub-1"],
  },
  {
    title: "1 × 3 = 3，减去 3，余 0",
    hint: "小棒操作：3 捆分完了，十位上没有剩余",
    highlightCells: ["mul-1", "sub-1", "sub-result-1", "remainder-1"],
  },
  {
    title: "落下个位 6，6 ÷ 3 = 2",
    hint: "小棒操作：把 6 根单根平均分给 3 个同学，每人 2 根",
    highlightCells: ["bring-down", "q-one", "r-one", "mul-2", "sub-2"],
  },
  {
    title: "2 × 3 = 6，减完余 0",
    hint: "小棒操作：6 根也分完了！每人分到 1 捆 + 2 根 = 12 根",
    highlightCells: ["mul-2", "sub-2", "sub-result-2", "remainder-2", "final-0"],
  },
];

type Phase = "sticks" | "division" | "done";

export default function CountPage() {
  const [phase, setPhase] = useState<Phase>("sticks");
  const [completeMsg, setCompleteMsg] = useState("");

  // ===== 阶段1：分小棒 =====
  const [distributionRound, setDistributionRound] = useState(0);
  const [animating, setAnimating] = useState(false);

  // 当前已分给每个同学的总量
  const [groupCounts, setGroupCounts] = useState([0, 0, 0]);
  const [groupBundles, setGroupBundles] = useState([0, 0, 0]);
  const [groupSingles, setGroupSingles] = useState([0, 0, 0]);
  const [remainingBundles, setRemainingBundles] = useState(3);
  const [remainingSingles, setRemainingSingles] = useState(6);

  const centerRef = useRef<HTMLDivElement>(null);

  const allDistributed =
    groupCounts[0] === 12 &&
    groupCounts[1] === 12 &&
    groupCounts[2] === 12;

  const onDistribute = () => {
    if (animating || allDistributed) return;
    setAnimating(true);

    // 36 根 = 3 捆(30) + 6 根单根
    // 分发逻辑：先分 3 捆，再分 6 根单根
    if (distributionRound === 0) {
      // 把 3 捆平均分：每人 1 捆（10 根）
      setGroupCounts((prev) => prev.map((c) => c + 10));
      setGroupBundles((prev) => prev.map((c) => c + 1));
      setRemainingBundles(0);
    } else if (distributionRound === 1) {
      // 把 6 根单根平均分：每人 2 根
      setGroupCounts((prev) => prev.map((c) => c + 2));
      setGroupSingles((prev) => prev.map((c) => c + 2));
      setRemainingSingles(0);
    }

    setTimeout(() => {
      setDistributionRound((prev) => prev + 1);
      setAnimating(false);
    }, 800);
  };

  const moveToPhase2 = () => {
    setPhase("division");
    setDivisionStep(0);
    setCompleteMsg(getRandomEncourage());
  };

  // ===== 阶段2：竖式 =====
  const [divisionStep, setDivisionStep] = useState(0);
  const divisionRef = useRef<HTMLDivElement>(null);

  const currentStep = DIVISION_STEPS[divisionStep];
  const allStepsDone = divisionStep >= DIVISION_STEPS.length;

  const onNextDivisionStep = () => {
    if (allStepsDone) return;
    if (divisionStep === DIVISION_STEPS.length - 1) {
      setDivisionStep(DIVISION_STEPS.length);
      setCompleteMsg(getRandomComplete());
      setTimeout(() => playCelebrate(), 300);
    } else {
      setDivisionStep((prev) => prev + 1);
      playStep();
    }
  };

  const nextStep = getNextStep("division", "count");

  // 竖式中某个单元格是否高亮
  const isHighlighted = (cellId: string) => {
    if (allStepsDone) return false;
    return currentStep.highlightCells.includes(cellId);
  };

  return (
    <StepShell topicId="division" stepId="count">
      {/* 阶段切换指示器 */}
      <div className="mb-6 flex items-center justify-center gap-2">
        {(["分小棒", "竖式记录"] as const).map((label, i) => {
          const phaseIdx = i === 0 ? "sticks" : "division";
          const isActive =
            phase === phaseIdx || (i === 1 && phase === "done");
          const isDone =
            (i === 0 && (phase === "division" || phase === "done")) ||
            (i === 1 && phase === "done");
          return (
            <div key={label} className="flex items-center gap-2">
              <div
                className={`rounded-full px-4 py-1.5 text-sm transition-colors ${
                  isActive
                    ? "bg-[var(--signal-focus)] font-semibold text-[var(--text)]"
                    : isDone
                    ? "bg-[var(--signal-confirmed)]/20 text-[var(--signal-confirmed)]"
                    : "bg-[var(--bg-soft)] text-[var(--text-muted)]"
                }`}
              >
                {isDone && !isActive ? "✓ " : ""}
                {label}
              </div>
              {i < 1 && <div className="h-px w-6 bg-[var(--border)]" />}
            </div>
          );
        })}
      </div>

      {/* ===== 阶段 1：分小棒 ===== */}
      {phase === "sticks" && (
        <div className="space-y-6">
          {/* 题目卡片 */}
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <div className="flex items-center gap-3">
              <span className="text-2xl">🧮</span>
              <div>
                <h2 className="text-lg font-semibold text-[var(--text)]">
                  36 ÷ 3 = ?
                </h2>
                <p className="mt-1 text-sm text-[var(--text-secondary)]">
                  把 36 根小棒平均分给 3 个同学，每人分到多少？
                </p>
              </div>
            </div>
          </div>

          {/* 小棒展示区 */}
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-4 shadow-[var(--shadow-sm)]">
            <p className="mb-3 text-center text-sm font-medium text-[var(--text-secondary)]">
              小棒区（剩余：{remainingBundles} 捆 + {remainingSingles} 根）
            </p>

            {/* 中心小棒展示 */}
            <div
              ref={centerRef}
              className="mx-auto mb-4 flex min-h-[80px] flex-wrap items-center justify-center gap-1 rounded-xl border-2 border-dashed border-[var(--border)] bg-[var(--bg-soft)] p-3"
            >
              {/* 整十捆 */}
              {Array.from({ length: remainingBundles }, (_, i) => (
                <div
                  key={`bundle-${i}`}
                  className={`flex items-center transition-all duration-500 ${
                    animating && distributionRound < 2
                      ? "scale-75 opacity-50"
                      : ""
                  }`}
                >
                  <svg width="40" height="20" viewBox="0 0 40 20">
                    <rect
                      x="0"
                      y="2"
                      width="36"
                      height="14"
                      rx="3"
                      fill="#F59E0B"
                      stroke="#D97706"
                      strokeWidth="1.5"
                    />
                    <text
                      x="18"
                      y="13"
                      textAnchor="middle"
                      fontSize="8"
                      fill="white"
                      fontWeight="bold"
                    >
                      10
                    </text>
                  </svg>
                </div>
              ))}

              {/* 单根 */}
              {Array.from({ length: remainingSingles }, (_, i) => (
                <div
                  key={`single-${i}`}
                  className={`transition-all duration-500 ${
                    animating && distributionRound === 1
                      ? "scale-75 opacity-50"
                      : ""
                  }`}
                >
                  <svg width="24" height="12" viewBox="0 0 24 12">
                    <rect
                      x="0"
                      y="1"
                      width="20"
                      height="8"
                      rx="2"
                      fill="#FB923C"
                      stroke="#EA580C"
                      strokeWidth="1"
                    />
                  </svg>
                </div>
              ))}

              {remainingBundles === 0 && remainingSingles === 0 && (
                <span className="text-sm text-[var(--text-muted)]">
                  全部分完了！
                </span>
              )}
            </div>

            {/* 3 个同学分区 */}
            <div className="grid grid-cols-3 gap-3">
              {[0, 1, 2].map((groupIdx) => (
                <div
                  key={groupIdx}
                  className="flex flex-col items-center rounded-xl border-2 border-[var(--border)] bg-[var(--bg-card)] p-3 transition-all duration-500"
                  style={{
                    borderColor:
                      groupCounts[groupIdx] > 0
                        ? `var(--accent${groupIdx === 0 ? "" : groupIdx === 1 ? "2" : "3"})`
                        : undefined,
                  }}
                >
                  {/* 同学头像圈 */}
                  <div
                    className="mb-2 flex h-10 w-10 items-center justify-center rounded-full text-lg"
                    style={{
                      backgroundColor:
                        groupIdx === 0
                          ? "var(--accent)"
                          : groupIdx === 1
                          ? "var(--accent2)"
                          : "var(--accent3)",
                      color: "white",
                    }}
                  >
                    {groupIdx === 0
                      ? "A"
                      : groupIdx === 1
                      ? "B"
                      : "C"}
                  </div>

                  {/* 分到的小棒 */}
                  <div className="flex min-h-[60px] flex-wrap items-center justify-center gap-1">
                    {/* 捆 */}
                    {Array.from(
                      { length: groupBundles[groupIdx] },
                      (_, i) => (
                        <div
                          key={`g${groupIdx}-b${i}`}
                          className="animate-float-in"
                        >
                          <svg width="36" height="18" viewBox="0 0 36 18">
                            <rect
                              x="0"
                              y="2"
                              width="32"
                              height="12"
                              rx="3"
                              fill="#F59E0B"
                              stroke="#D97706"
                              strokeWidth="1"
                            />
                          </svg>
                        </div>
                      )
                    )}
                    {/* 单根 */}
                    {Array.from(
                      { length: groupSingles[groupIdx] },
                      (_, i) => (
                        <div
                          key={`g${groupIdx}-s${i}`}
                          className="animate-float-in"
                        >
                          <svg width="20" height="10" viewBox="0 0 20 10">
                            <rect
                              x="0"
                              y="1"
                              width="16"
                              height="7"
                              rx="2"
                              fill="#FB923C"
                              stroke="#EA580C"
                              strokeWidth="1"
                            />
                          </svg>
                        </div>
                      )
                    )}
                  </div>

                  {/* 数量 */}
                  <span className="mt-1 text-sm font-bold text-[var(--text)]">
                    {groupCounts[groupIdx] > 0
                      ? `${groupCounts[groupIdx]} 根`
                      : "等待分配"}
                  </span>
                </div>
              ))}
            </div>
          </div>

          {/* 分配按钮 */}
          {!allDistributed && (
            <div className="flex flex-col items-center gap-3">
              <button
                onClick={onDistribute}
                disabled={animating}
                className={`rounded-full px-8 py-3 text-lg font-semibold text-white shadow-[var(--shadow-accent)] transition-all ${
                  animating
                    ? "cursor-wait opacity-60"
                    : "hover:scale-105 active:scale-95"
                }`}
                style={{ backgroundColor: "var(--accent)" }}
              >
                {distributionRound === 0
                  ? "分一捆（每人 10 根）"
                  : "分单根（每人 2 根）"}
              </button>
              {animating && (
                <p className="animate-bounce-soft text-sm text-[var(--text-secondary)]">
                  正在分配中...
                </p>
              )}
            </div>
          )}

          {/* 分完后的总结 */}
          {allDistributed && (
            <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
              <div className="text-4xl">🎉</div>
              <p className="mt-2 text-lg font-semibold text-[var(--text)]">
                分完了！
              </p>
              <div className="mt-2 flex justify-center gap-4 text-sm text-[var(--text-secondary)]">
                <span>
                  A 同学：1 捆 + 2 根 ={" "}
                  <strong className="text-[var(--accent)]">12 根</strong>
                </span>
                <span>
                  B 同学：1 捆 + 2 根 ={" "}
                  <strong className="text-[var(--accent2)]">12 根</strong>
                </span>
                <span>
                  C 同学：1 捆 + 2 根 ={" "}
                  <strong className="text-[var(--accent3)]">12 根</strong>
                </span>
              </div>
              <p className="mt-3 text-xl font-bold text-[var(--primary)]">
                36 ÷ 3 = 12
              </p>
              <button
                onClick={moveToPhase2}
                className="mt-4 rounded-full bg-[var(--primary)] px-8 py-3 font-medium text-white transition-all hover:scale-105"
              >
                用竖式记录下来 →
              </button>
            </div>
          )}
        </div>
      )}

      {/* ===== 阶段 2：竖式记录 ===== */}
      {phase === "division" && (
        <div className="space-y-6">
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <h2 className="text-lg font-semibold text-[var(--text)]">
              竖式记录 36 ÷ 3
            </h2>
            <p className="mt-1 text-sm text-[var(--text-secondary)]">
              点击"下一步"，看看竖式的每一步是怎么算的
            </p>
          </div>

          {/* 竖式展示 */}
          <div ref={divisionRef} className="flex justify-center">
            <div className="rounded-[var(--radius)] border-2 border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              {/* 用 SVG 绘制竖式 */}
              <svg width="220" height="280" viewBox="0 0 220 280">
                {/* 字体样式 */}
                <style>{`
                  .digit { font-family: monospace; font-size: 28px; fill: var(--text); font-weight: bold; }
                  .digit-highlight { font-family: monospace; font-size: 28px; font-weight: bold; }
                  .digit-dim { font-family: monospace; font-size: 28px; fill: var(--text-muted); }
                  .op { font-family: monospace; font-size: 28px; fill: var(--text); font-weight: bold; }
                  .line { stroke: var(--text); stroke-width: 2; }
                  .line-dim { stroke: var(--text-muted); stroke-width: 2; stroke-dasharray: 4 3; }
                  .bg-highlight { rx: 6; ry: 6; }
                `}</style>

                {/* 高亮背景层 */}
                {/* 步骤1: 十位的商1, 1x3=3, 减3 */}
                {!allStepsDone && isHighlighted("q-ten") && (
                  <rect x="48" y="8" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("r-ten") && (
                  <rect x="88" y="8" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("mul-1") && (
                  <rect x="88" y="68" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("sub-1") && (
                  <rect x="28" y="68" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("sub-result-1") && (
                  <rect x="128" y="68" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("remainder-1") && (
                  <rect x="68" y="68" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}

                {/* 步骤3: 个位的商2, 落下6, 2x3=6 */}
                {!allStepsDone && isHighlighted("q-one") && (
                  <rect x="78" y="8" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("r-one") && (
                  <rect x="118" y="8" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("bring-down") && (
                  <rect x="118" y="48" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("mul-2") && (
                  <rect x="118" y="128" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("sub-2") && (
                  <rect x="58" y="128" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("sub-result-2") && (
                  <rect x="158" y="128" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("remainder-2") && (
                  <rect x="98" y="128" width="28" height="32" className="bg-highlight" fill="var(--signal-focus)" opacity="0.3" />
                )}
                {!allStepsDone && isHighlighted("final-0") && (
                  <rect x="158" y="188" width="28" height="32" className="bg-highlight" fill="var(--signal-success)" opacity="0.3" />
                )}

                {/* 数字层 */}
                {/* 商: 1 2 */}
                <text id="q-ten" x="55" y="32" textAnchor="middle" className={divisionStep >= 1 || allStepsDone ? "digit" : "digit-dim"}>1</text>
                <text id="q-one" x="85" y="32" textAnchor="middle" className={divisionStep >= 3 || allStepsDone ? "digit" : "digit-dim"}>2</text>

                {/* 除号和被除数: 3 | 3 6 */}
                <text x="28" y="72" textAnchor="middle" className="op">3</text>
                <line x1="40" y1="52" x2="40" y2="82" className="line" />
                <line x1="40" y1="52" x2="140" y2="52" className="line" />

                <text id="r-ten" x="95" y="72" textAnchor="middle" className="digit">3</text>
                <text id="r-one" x="125" y="72" textAnchor="middle" className="digit">6</text>

                {/* 第一行减法: 3 */}
                <text id="mul-1" x="95" y="112" textAnchor="middle" className={divisionStep >= 1 || allStepsDone ? "digit" : "digit-dim"}>3</text>
                <text id="sub-1" x="35" y="112" textAnchor="middle" className={divisionStep >= 1 || allStepsDone ? "digit" : "digit-dim"}>−</text>
                <text id="sub-result-1" x="140" y="112" textAnchor="middle" className={divisionStep >= 2 || allStepsDone ? "digit" : "digit-dim"}>0</text>
                <text id="remainder-1" x="80" y="112" textAnchor="middle" className={divisionStep >= 2 || allStepsDone ? "digit" : "digit-dim"}> </text>
                <line x1="25" y1="120" x2="150" y2="120" className={divisionStep >= 2 || allStepsDone ? "line" : "line-dim"} />

                {/* 落下个位 6 */}
                <text id="bring-down" x="125" y="152" textAnchor="middle" className={divisionStep >= 3 || allStepsDone ? "digit" : "digit-dim"}>6</text>
                <text x="55" y="152" textAnchor="middle" className={divisionStep >= 3 || allStepsDone ? "digit" : "digit-dim"}>0</text>
                <text x="85" y="152" textAnchor="middle" className={divisionStep >= 3 || allStepsDone ? "digit" : "digit-dim"}> </text>

                {/* 第二行减法: 6 */}
                <text id="mul-2" x="125" y="192" textAnchor="middle" className={divisionStep >= 3 || allStepsDone ? "digit" : "digit-dim"}>6</text>
                <text id="sub-2" x="65" y="192" textAnchor="middle" className={divisionStep >= 3 || allStepsDone ? "digit" : "digit-dim"}>−</text>
                <text id="sub-result-2" x="170" y="192" textAnchor="middle" className={divisionStep >= 4 || allStepsDone ? "digit" : "digit-dim"}>0</text>
                <line x1="55" y1="200" x2="180" y2="200" className={divisionStep >= 4 || allStepsDone ? "line" : "line-dim"} />

                {/* 最终余数 0 */}
                <text id="final-0" x="170" y="235" textAnchor="middle" className={divisionStep >= 4 || allStepsDone ? "digit" : "digit-dim"}>0</text>
              </svg>
            </div>
          </div>

          {/* 步骤提示 */}
          {!allStepsDone && (
            <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-4 shadow-[var(--shadow-sm)]">
              <p className="text-center text-lg font-semibold text-[var(--text)]">
                步骤 {divisionStep + 1}/{DIVISION_STEPS.length}：{currentStep.title}
              </p>
              <p className="mt-2 text-center text-sm text-[var(--text-secondary)]">
                {currentStep.hint}
              </p>
            </div>
          )}

          {/* 下一步按钮 */}
          {!allStepsDone && (
            <div className="flex justify-center">
              <button
                onClick={onNextDivisionStep}
                className="rounded-full bg-[var(--primary)] px-8 py-3 text-lg font-semibold text-white shadow-[var(--shadow-md)] transition-all hover:scale-105 active:scale-95"
              >
                下一步 →
              </button>
            </div>
          )}

          {/* 步骤完成后的完成卡片 */}
          {allStepsDone && (
            <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
              <div className="text-4xl">🎉</div>
              <p className="mt-2 text-lg font-semibold text-[var(--text)]">
                竖式完成了！
              </p>
              <p className="mt-1 text-2xl font-bold text-[var(--primary)]">
                36 ÷ 3 = 12
              </p>
              <p className="mt-2 text-sm text-[var(--text-secondary)]">
                {completeMsg}
              </p>
              <p className="mt-2 text-sm text-[var(--text-secondary)]">
                小棒分法和竖式记录，每一步都对应上了！
              </p>
              <div className="mt-4 flex justify-center gap-3">
                <button
                  onClick={() => {
                    setDivisionStep(0);
                    setCompleteMsg(getRandomEncourage());
                  }}
                  className="rounded-full bg-[var(--bg-soft)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--border)]"
                >
                  再看一遍
                </button>
                {nextStep && (
                  <Link
                    href={nextStep.path}
                    className="rounded-full bg-[var(--accent)] px-8 py-3 font-medium text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                  >
                    下一步：{nextStep.label} →
                  </Link>
                )}
              </div>
            </div>
          )}
        </div>
      )}
    </StepShell>
  );
}
